The `debounce` function is a utility function that limits the rate at which a given function can be called, preventing excessive invocations within a short time frame.

```javascript
function debounce(callback, delay) {
  let timeoutId;
  return function(...args) {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      callback(...args);
    }, delay);
  };
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
debouncedLog('Hello'); // This will log 'Hello' to the console after 500ms
debouncedLog('World'); // This will clear the previous timeout and log 'World' to the console after 500ms
```
